db = Polymake.Polydb.get_db()
collection = db["Matroids.Small"]

results = Polymake.Polydb.find(collection, Dict("RANK" => 3, "N_ELEMENTS" => 11))

matroid_list = results

csv_str = ""

lst = []
dims = []
for matroid in matroid_list
    matroid = Matroid(matroid)
    H = hyperplanes(matroid)
    three = 0
    two = 0 
    for l in H
        if length(l) == 2
            two += 1
        elseif length(l) == 3
            three += 1
        end
    end
    if three == 11 && two == 22
        points = Dict()
        for l in H
            if length(l) == 3
                for p in l
                    points[p] = get(points, p, 0) + 1
                end
            end
        end
        con = true
        count = 0
        for item in points
            p = item[1]
            c = item[2]
            if c == 3
                count += 1
            else
                con = false
            end
        end
        
        if con && count == 11
            push!(lst, matroid)
            try
                R = realization_space(matroid, ground_ring = QQ)
                display(R)
                push!(dims, dim(R))
            catch
                continue
            end
        end
    end
end
